def dieSimulator(n, rollMax):
    MOD = 10**9 + 7
    dp = [[0]*16 for _ in range(7)]
    for i in range(1,7): dp[i][1] = 1
    for _ in range(1, n):
        new_dp = [[0]*16 for _ in range(7)]
        for last in range(1, 7):
            for k in range(1, rollMax[last-1]+1):
                if dp[last][k] == 0: continue
                for cur in range(1, 7):
                    if cur != last: new_dp[cur][1] = (new_dp[cur][1] + dp[last][k]) % MOD
                    elif k < rollMax[last-1]: new_dp[cur][k+1] = (new_dp[cur][k+1] + dp[last][k]) % MOD
        dp = new_dp
    return sum(sum(row) for row in dp) % MOD

